### New File: `src/services/productService.ts`

This file extracts all business logic from the three product route handlers.

```typescript
import { products } from "../data.js";
import type {
  ServiceResult,
  ProductListResult,
  ProductDetailResult,
  ProductListFilters,
} from "../types.js";

export function listProducts(filters: ProductListFilters): ServiceResult<ProductListResult> {
  let filtered = [...products];

  if (filters.category) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }

  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }

  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    success: true,
    data: {
      products: filtered,
      summary: {
        count: filtered.length,
        totalInventoryValue: Math.round(totalValue * 100) / 100,
        averagePrice: Math.round(avgPrice * 100) / 100,
      },
    },
  };
}

export function getProduct(id: number): ServiceResult<ProductDetailResult> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return {
      success: false,
      error: { code: "NOT_FOUND", message: "Product not found" },
    };
  }

  return {
    success: true,
    data: {
      ...product,
      isLowStock: product.stock < 10,
      inventoryValue: Math.round(product.price * product.stock * 100) / 100,
    },
  };
}

export function adjustStock(
  id: number,
  adjustment: number
): ServiceResult<ProductDetailResult> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return {
      success: false,
      error: { code: "NOT_FOUND", message: "Product not found" },
    };
  }

  if (typeof adjustment !== "number") {
    return {
      success: false,
      error: { code: "VALIDATION_ERROR", message: "adjustment must be a number" },
    };
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    return {
      success: false,
      error: { code: "INSUFFICIENT_STOCK", message: "Insufficient stock" },
    };
  }

  product.stock = newStock;

  return {
    success: true,
    data: {
      ...product,
      isLowStock: product.stock < 10,
      inventoryValue: Math.round(product.price * product.stock * 100) / 100,
    },
  };
}
```

Key observations about this extraction:
- `listProducts` receives already-parsed numeric filters. The route handler is responsible for `parseFloat` and the `typeof === "string"` checks on query params, since query string parsing is HTTP-layer concern.
- `getProduct` and `adjustStock` receive a numeric `id` (the route parses `parseInt`).
- The `typeof adjustment !== "number"` check stays in the service because it is a business validation (the service does not trust its callers), but in practice the route will also perform this check since it needs to map the error to a 400 status.

---

### New File: `src/services/orderService.ts`

This file extracts all business logic from the four order route handlers.

```typescript
import { orders, products, getNextOrderId } from "../data.js";
import type {
  CreateOrderInput,
  Order,
  OrderItem,
  ServiceResult,
  OrderListResult,
  OrderDetailResult,
  OrderListFilters,
} from "../types.js";

export function listOrders(filters: OrderListFilters): ServiceResult<OrderListResult> {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    success: true,
    data: {
      orders: filtered,
      summary: {
        count: filtered.length,
        totalRevenue: Math.round(totalRevenue * 100) / 100,
      },
    },
  };
}

export function getOrder(id: number): ServiceResult<OrderDetailResult> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return {
      success: false,
      error: { code: "NOT_FOUND", message: "Order not found" },
    };
  }

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    success: true,
    data: {
      ...order,
      items: enrichedItems,
    },
  };
}

export function createOrder(input: CreateOrderInput): ServiceResult<Order> {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    return {
      success: false,
      error: { code: "VALIDATION_ERROR", message: "userId and items are required" },
    };
  }

  if (input.items.length === 0) {
    return {
      success: false,
      error: { code: "VALIDATION_ERROR", message: "Order must have at least one item" },
    };
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      return {
        success: false,
        error: {
          code: "VALIDATION_ERROR",
          message: `Product ${item.productId} not found`,
        },
      };
    }

    if (item.quantity <= 0) {
      return {
        success: false,
        error: { code: "VALIDATION_ERROR", message: "Quantity must be positive" },
      };
    }

    if (product.stock < item.quantity) {
      return {
        success: false,
        error: {
          code: "INSUFFICIENT_STOCK",
          message: `Insufficient stock for ${product.name}`,
        },
      };
    }

    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return { success: true, data: order };
}

export function updateOrderStatus(
  id: number,
  status: string
): ServiceResult<Order> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return {
      success: false,
      error: { code: "NOT_FOUND", message: "Order not found" },
    };
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];
  if (!validStatuses.includes(status)) {
    return {
      success: false,
      error: {
        code: "VALIDATION_ERROR",
        message: `Invalid status. Must be one of: ${validStatuses.join(", ")}`,
      },
    };
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    return {
      success: false,
      error: {
        code: "INVALID_TRANSITION",
        message: `Cannot transition from ${order.status} to ${status}`,
      },
    };
  }

  order.status = status as typeof order.status;

  return { success: true, data: order };
}
```

