  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }

  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    success: true,
    data: {
      products: filtered,
      summary: {
        count: filtered.length,
        totalInventoryValue: Math.round(totalValue * 100) / 100,
        averagePrice: Math.round(avgPrice * 100) / 100,
      },
    },
  };
}

export function getProduct(id: number): ServiceResult<ProductDetailResult> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return {
      success: false,
      error: { code: "NOT_FOUND", message: "Product not found" },
    };
  }

  return {
    success: true,
    data: {
      ...product,
      isLowStock: product.stock < 10,
      inventoryValue: Math.round(product.price * product.stock * 100) / 100,
    },
  };
}

export function adjustStock(
  id: number,
  adjustment: number
): ServiceResult<ProductDetailResult> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return {
      success: false,
      error: { code: "NOT_FOUND", message: "Product not found" },
    };
  }

  if (typeof adjustment !== "number") {
    return {
      success: false,
      error: { code: "VALIDATION_ERROR", message: "adjustment must be a number" },
    };
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    return {
      success: false,
      error: { code: "INSUFFICIENT_STOCK", message: "Insufficient stock" },
    };
  }

  product.stock = newStock;

  return {
    success: true,
    data: {
      ...product,
      isLowStock: product.stock < 10,
      inventoryValue: Math.round(product.price * product.stock * 100) / 100,
    },
  };
}
```

Key observations about this extraction:
- `listProducts` receives already-parsed numeric filters. The route handler is responsible for `parseFloat` and the `typeof === "string"` checks on query params, since query string parsing is HTTP-layer concern.
- `getProduct` and `adjustStock` receive a numeric `id` (the route parses `parseInt`).
- The `typeof adjustment !== "number"` check stays in the service because it is a business validation (the service does not trust its callers), but in practice the route will also perform this check since it needs to map the error to a 400 status.

