### New File: `src/services/orderService.ts`

This file extracts all business logic from the four order route handlers.

```typescript
import { orders, products, getNextOrderId } from "../data.js";
import type {
  CreateOrderInput,
  Order,
  OrderItem,
  ServiceResult,
  OrderListResult,
  OrderDetailResult,
  OrderListFilters,
} from "../types.js";

export function listOrders(filters: OrderListFilters): ServiceResult<OrderListResult> {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    success: true,
    data: {
      orders: filtered,
      summary: {
        count: filtered.length,
        totalRevenue: Math.round(totalRevenue * 100) / 100,
      },
    },
  };
}

export function getOrder(id: number): ServiceResult<OrderDetailResult> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return {
      success: false,
      error: { code: "NOT_FOUND", message: "Order not found" },
    };
  }

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    success: true,
    data: {
      ...order,
      items: enrichedItems,
    },
  };
}

export function createOrder(input: CreateOrderInput): ServiceResult<Order> {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    return {
      success: false,
      error: { code: "VALIDATION_ERROR", message: "userId and items are required" },
    };
  }

  if (input.items.length === 0) {
    return {
      success: false,
      error: { code: "VALIDATION_ERROR", message: "Order must have at least one item" },
    };
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      return {
        success: false,
        error: {
          code: "VALIDATION_ERROR",
          message: `Product ${item.productId} not found`,
        },
      };
    }

    if (item.quantity <= 0) {
      return {
        success: false,
        error: { code: "VALIDATION_ERROR", message: "Quantity must be positive" },
      };
    }

    if (product.stock < item.quantity) {
      return {
        success: false,
        error: {
          code: "INSUFFICIENT_STOCK",
          message: `Insufficient stock for ${product.name}`,
        },
      };
    }

    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return { success: true, data: order };
}

export function updateOrderStatus(
  id: number,
  status: string
): ServiceResult<Order> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return {
      success: false,
      error: { code: "NOT_FOUND", message: "Order not found" },
    };
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];
  if (!validStatuses.includes(status)) {
    return {
      success: false,
      error: {
        code: "VALIDATION_ERROR",
        message: `Invalid status. Must be one of: ${validStatuses.join(", ")}`,
      },
    };
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    return {
      success: false,
      error: {
        code: "INVALID_TRANSITION",
        message: `Cannot transition from ${order.status} to ${status}`,
      },
    };
  }

  order.status = status as typeof order.status;

  return { success: true, data: order };
}
```

