### Modified File: `src/routes/products.ts` (Thin Route Layer)

The route handlers shrink to pure request-parsing and response-mapping:

```typescript
import { Router } from "express";
import * as productService from "../services/productService.js";

const router = Router();

const errorStatusMap: Record<string, number> = {
  NOT_FOUND: 404,
  VALIDATION_ERROR: 400,
  INSUFFICIENT_STOCK: 400,
};

router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const filters: { category?: string; minPrice?: number; maxPrice?: number } = {};

  if (category && typeof category === "string") {
    filters.category = category;
  }
  if (minPrice && typeof minPrice === "string") {
    const min = parseFloat(minPrice);
    if (!isNaN(min)) filters.minPrice = min;
  }
  if (maxPrice && typeof maxPrice === "string") {
    const max = parseFloat(maxPrice);
    if (!isNaN(max)) filters.maxPrice = max;
  }

  const result = productService.listProducts(filters);
  // listProducts always succeeds, but we keep the pattern consistent
  if (!result.success) {
    res.status(errorStatusMap[result.error.code] ?? 500).json({ error: result.error.message });
    return;
  }
  res.json(result.data);
});

router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const result = productService.getProduct(id);

  if (!result.success) {
    res.status(errorStatusMap[result.error.code] ?? 500).json({ error: result.error.message });
    return;
  }
  res.json(result.data);
});

router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: number };

  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" });
    return;
  }

  const result = productService.adjustStock(id, adjustment);

  if (!result.success) {
    res.status(errorStatusMap[result.error.code] ?? 500).json({ error: result.error.message });
    return;
  }
  res.json(result.data);
});

export { router as productRouter };
```

Notable details:
- Query string parsing (`typeof === "string"`, `parseFloat`) stays in the route because it is HTTP-specific (Express query params are `string | undefined`).
- The `typeof adjustment !== "number"` check is kept in the route as an early guard for malformed HTTP bodies. The service also validates this defensively, but the route check means we never call the service with bad data.
- The `errorStatusMap` centralizes the mapping from semantic error codes to HTTP status codes.

